		score float64
		isNew bool
	}
	var candidates []candidate

	const alpha = 1.5
	const beta = 0.3
	baseDist := cal_dis(ori, des)

	for ii := 0; ii < dispatch.AssignsLen; ii++ {
		oldCost := dispatch.Assigns[ii].Cost
		assignCopy := dispatch.Assigns[ii]
		ok := assignCopy.AddShip(shipID, ori, des)
		if ok {
			assignCopy.GenRoute()
			newCost := assignCopy.Cost
			delta := newCost - oldCost
			incremental := delta / (baseDist + 1e-9)
			penalty := 0.0
			if incremental > 0 {
				penalty = math.Pow(incremental, alpha)
			}
			score := delta + beta*penalty
			candidates = append(candidates, candidate{idx: ii, score: score, isNew: false})
		}
	}

	if dispatch.AssignsLen < MAXASSIGNS {
		emptyIdx := dispatch.AssignsLen
		assignCopy := dispatch.Assigns[emptyIdx]
		ok := assignCopy.AddShip(shipID, ori, des)
		if ok {
			assignCopy.GenRoute()
			newCost := assignCopy.Cost
			if newCost >= 0 {
				score := newCost * (1.0 + beta)
				candidates = append(candidates, candidate{idx: emptyIdx, score: score, isNew: true})
			}
		}
	}

	inserted := false
	const eps = 1e-12
	bestIdx := -1
	if len(candidates) > 0 {
		minScore := candidates[0].score
		bestIsNew := candidates[0].isNew
		bestIdx = candidates[0].idx
		for _, cand := range candidates[1:] {
			if cand.score < minScore-eps {
				minScore = cand.score
				bestIsNew = cand.isNew
				bestIdx = cand.idx
			} else if cand.score < minScore+eps && !cand.isNew && bestIsNew {
				minScore = cand.score
				bestIsNew = false
				bestIdx = cand.idx
			}
		}
		ok := dispatch.Assigns[bestIdx].AddShip(shipID, ori, des)
		if ok {
			dispatch.Assigns[bestIdx].GenRoute()
			if bestIdx >= dispatch.AssignsLen {
				dispatch.AssignsLen++
			}
			inserted = true
		}
	}

	if !inserted {
		fallbackOrder := make([]int, 0, MAXASSIGNS)
		for ii := 0; ii < dispatch.AssignsLen; ii++ {
			fallbackOrder = append(fallbackOrder, ii)
		}
		sort.SliceStable(fallbackOrder, func(i, j int) bool {
			return dispatch.Assigns[fallbackOrder[i]].Cost < dispatch.Assigns[fallbackOrder[j]].Cost
		})

		done := false
		for _, ii := range fallbackOrder {
			ok := dispatch.Assigns[ii].AddShip(shipID, ori, des)
